import type Accessor from "../../core/Accessor.js";
import type GamepadSettings from "./gamepad/GamepadSettings.js";

export interface InputProperties {}

/**
 * Input device related configuration settings on the View.
 *
 * @since 4.9
 */
export default class Input extends Accessor {
  constructor(properties?: InputProperties);
  /**
   * Gamepad input specific configuration settings.
   *
   * @since 4.9
   */
  get gamepad(): GamepadSettings;
}